mapper.select:
SELECT
user_id AS userId,
ANY_VALUE(currency) AS currency,
max(user_account) AS userAccount,
IFNULL(SUM(bet_amount), 0) AS betAmount,
IFNULL(SUM(win_loss_amount), 0) AS winLossAmount,
IFNULL(SUM(valid_amount), 0) AS validAmount
FROM
report_user_venue_win_lose


        site_code = #{vo.siteCode}



        AND venue_code = #{vo.venueCode}



        AND venue_code in

            #{venueCode}





        AND user_id = #{vo.userId}


        AND day_hour_millis  >=  #{vo.startTime}


        AND day_hour_millis  <=  #{vo.endTime}



        AND day_millis  >=  #{vo.dayMillisStartTime}


        AND day_millis  <   #{vo.dayMillisEndTime}



        AND bet_amount  >=  #{vo.startTotalBetAmount}


        AND bet_amount  <=  #{vo.endTotalBetAmount}



        AND day_millis = #{vo.dayMillis}


GROUP BY user_id

SELECT tab.currency
FROM (
         SELECT currency, COUNT(day_millis) AS countDay
         FROM report_user_venue_win_lose
         WHERE day_millis BETWEEN #{vo.startDayMillisTime} AND #{vo.endDayMillisTime}
           AND venue_type = #{vo.venueType}
           AND site_code = #{vo.siteCode}
         GROUP BY currency
         HAVING COUNT(day_millis) >= #{vo.countDay}
     ) AS tab;

select *
from (SELECT day_tab.user_id, count(day_tab.user_id) as userCount
      FROM (SELECT user_id, SUM(valid_amount) AS totalAmount
            FROM report_user_venue_win_lose
            WHERE day_millis BETWEEN #{vo.startDayMillisTime} AND #{vo.endDayMillisTime} -- 替换为开始和结束的时间戳
              and currency = #{vo.currencyCode}
              and venue_type = #{vo.venueType}
              and site_code = #{vo.siteCode}
            GROUP BY user_id, day_millis
            HAVING totalAmount >= #{vo.platformDayBetAmount}) day_tab
      group by day_tab.user_id) cou_tab
where cou_tab.userCount >= #{vo.countDay}

SELECT site_code,user_id,day_millis,venue_code,user_account,currency, SUM(win_loss_amount) as winLossAmount ,SUM(valid_amount) as validAmount, SUM(bet_amount) as betAmount FROM report_user_venue_win_lose WHERE site_code = #{vo.siteCode} and day_millis = #{vo.dayMillis}
AND venue_code in
#{venueCode}
AND user_id in
#{userId}
group by site_code,user_id,day_millis,venue_code,user_account,currency

SELECT site_code,day_millis,venue_code,currency, SUM(win_loss_amount) as winLossAmount ,SUM(valid_amount) as validAmount, SUM(bet_amount) as betAmount FROM report_user_venue_win_lose WHERE site_code = #{vo.siteCode} and day_millis = #{vo.dayMillis}
AND venue_code in
#{venueCode}
GROUP BY site_code,day_millis,venue_code,currency

SELECT site_code,user_id,day_millis,venue_code,user_account,currency,
SUM(win_loss_amount) as winLossAmount
,SUM(valid_amount) as validAmount,
SUM(bet_amount) as betAmount
FROM report_user_venue_win_lose
WHERE site_code = #{vo.siteCode} and day_millis = #{vo.dayMillis}


    AND venue_code in

        #{venueCode}




    AND user_id = #{vo.userId}

GROUP BY user_id,site_code,day_millis,venue_code,user_account,currency

SELECT
userId,
userAccount,
betAmount,
winLossAmount,
validAmount,currency
FROM
(
SELECT
user_id AS userId,
max(user_account) AS userAccount,
IFNULL(SUM(bet_amount), 0) AS betAmount,
IFNULL(SUM(win_loss_amount), 0) AS winLossAmount,
IFNULL(SUM(valid_amount), 0) AS validAmount
,currency
FROM
report_user_venue_win_lose
WHERE
site_code = #{vo.siteCode}

    AND venue_code = #{vo.venueCode}


    AND user_id IN

        #{value}



    AND venue_code IN

        #{value}



    AND day_millis = #{vo.dayMillis}



    AND day_hour_millis  >=  #{vo.startTime}



    AND day_hour_millis  <=  #{vo.endTime}


GROUP BY
user_id,currency
) t


        AND t.winLossAmount  >=  #{vo.winLossAmountMin}


        AND t.winLossAmount  <=  #{vo.winLossAmountMax}


        AND t.betAmount  >=  #{vo.betAmountMin}


        AND t.betAmount  <=  #{vo.betAmountMax}



    order by ${vo.orderField}

        ${vo.orderType}
